import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getChannels } from '../services/api';

const Home = () => {
  const [channels, setChannels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('Todos');

  const categories = ['Todos', 'Noticias', 'Entretenimiento', 'Deportes', 'Música', 'Radio', 'Infantil', 'Documentales'];

  useEffect(() => {
    loadChannels();
  }, []);

  const loadChannels = async () => {
    try {
      const data = await getChannels({});
      setChannels(data);
    } catch (error) {
      console.error('Error cargando canales:', error);
    } finally {
      setLoading(false);
    }
  };

  const filtered = channels.filter(c => {
    const matchSearch = c.name.toLowerCase().includes(search.toLowerCase());
    const matchCategory = activeCategory === 'Todos' || c.category === activeCategory;
    return matchSearch && matchCategory;
  });

  const tvChannels = filtered.filter(c => c.category !== 'Radio');
  const radioChannels = filtered.filter(c => c.category === 'Radio');

  if (loading) return (
    <div className="flex justify-center items-center h-[70vh]">
      <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-red-600"></div>
    </div>
  );

  const ChannelGrid = ({ title, items }) => (
    items.length > 0 && (
      <div className="mb-10 px-6">
        <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
          <span className="w-1.5 h-6 bg-red-600 rounded-full inline-block"></span>
          {title}
        </h2>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {items.map(channel => (
            <Link
              key={channel.id}
              to={`/player/channel/${channel.id}`}
              className="bg-gray-800 hover:bg-gray-700 rounded-xl p-4 flex flex-col items-center gap-3 transition-all hover:scale-105 hover:ring-2 hover:ring-red-600"
            >
              {channel.logo ? (
                <img
                  src={channel.logo}
                  alt={channel.name}
                  className="w-16 h-16 object-contain bg-white rounded-lg p-1"
                  onError={(e) => { e.target.style.display = 'none'; }}
                />
              ) : (
                <div className="w-16 h-16 bg-gray-600 rounded-lg flex items-center justify-center text-2xl">
                  {channel.category === 'Radio' ? '📻' : '📺'}
                </div>
              )}
              <span className="text-sm font-medium text-center truncate w-full text-center">{channel.name}</span>
              <span className="text-xs text-gray-400">{channel.country}</span>
            </Link>
          ))}
        </div>
      </div>
    )
  );

  return (
    <div className="pb-10">
      {/* Hero */}
      <div className="bg-gradient-to-b from-gray-800 to-gray-900 px-6 py-10 mb-8 text-center">
        <h1 className="text-4xl font-bold mb-2">RaulFlix</h1>
        <p className="text-gray-400 mb-6">TV en vivo y Radio online</p>
        <input
          type="text"
          placeholder="Buscar canal o radio..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full max-w-md px-4 py-3 bg-gray-700 rounded-full border border-gray-600 focus:outline-none focus:border-red-600 text-white"
        />
      </div>

      {/* Categorías */}
      <div className="flex gap-2 px-6 mb-8 overflow-x-auto pb-2">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
              activeCategory === cat
                ? 'bg-red-600 text-white'
                : 'bg-gray-700 hover:bg-gray-600 text-gray-300'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      <ChannelGrid title="📺 Canales de TV" items={tvChannels} />
      <ChannelGrid title="📻 Radio" items={radioChannels} />

      {filtered.length === 0 && (
        <div className="text-center py-16 text-gray-400">
          <p className="text-xl mb-2">No se encontraron resultados</p>
          <p className="text-sm">Intenta con otro término de búsqueda</p>
        </div>
      )}
    </div>
  );
};

export default Home;
